import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Badge } from '@/components/ui/badge'
import useOrderStore from '@/stores/useOrderStore'

export default function AdminOrders() {
  const { orders } = useOrderStore()

  return (
    <div className="animate-fade-in">
      <div className="mb-6">
        <h1 className="text-3xl font-heading font-bold mb-1">Pedidos</h1>
        <p className="text-muted-foreground">Gerencie as compras dos clientes na loja.</p>
      </div>

      <div className="bg-card rounded-xl border shadow-subtle overflow-hidden">
        <Table>
          <TableHeader className="bg-muted/50">
            <TableRow>
              <TableHead>ID Pedido</TableHead>
              <TableHead>Data</TableHead>
              <TableHead>Cliente (E-mail)</TableHead>
              <TableHead>Itens Comprados</TableHead>
              <TableHead>Cupom</TableHead>
              <TableHead className="text-right">Total</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {orders.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} className="text-center py-12 text-muted-foreground">
                  Nenhum pedido encontrado.
                </TableCell>
              </TableRow>
            ) : (
              orders.map((order) => (
                <TableRow key={order.id} className="group">
                  <TableCell className="font-medium">{order.id}</TableCell>
                  <TableCell className="whitespace-nowrap">
                    {new Date(order.date).toLocaleDateString('pt-BR')}
                  </TableCell>
                  <TableCell>
                    <div className="flex flex-col">
                      <span className="font-medium text-sm text-foreground">
                        {order.customerName}
                      </span>
                      <span className="text-xs text-muted-foreground">{order.customerEmail}</span>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="text-sm space-y-1">
                      {order.items.map((item, idx) => (
                        <div
                          key={idx}
                          className="truncate max-w-[200px] xl:max-w-[300px]"
                          title={item.title}
                        >
                          {item.quantity}x {item.title}
                        </div>
                      ))}
                    </div>
                  </TableCell>
                  <TableCell>
                    {order.couponApplied ? (
                      <Badge variant="secondary" className="font-mono text-xs">
                        {order.couponApplied}
                      </Badge>
                    ) : (
                      <span className="text-muted-foreground text-xs">-</span>
                    )}
                  </TableCell>
                  <TableCell className="text-right font-bold text-primary">
                    R$ {order.total.toFixed(2).replace('.', ',')}
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>
    </div>
  )
}
